/* ===== PILL DATE PICKER (Daily) ===== */
var _calY,_calM;
function pillDateH(){
var d=viewDate,day=THDAY[d.getDay()],dd=d.getDate(),mm=TMF[d.getMonth()],yy=d.getFullYear();
return '<div class="pill-date"><div class="pill-btn" onclick="openCal()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M3 10h18M8 2v4M16 2v4"/></svg><span>'+day+' '+dd+' '+mm+' '+yy+'</span><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="6 9 12 15 18 9"/></svg></div></div>'}
function openCal(){_calY=viewDate.getFullYear();_calM=viewDate.getMonth();renderCal();document.getElementById('calPop').classList.add('open')}
function closeCal(){document.getElementById('calPop').classList.remove('open')}
document.getElementById('calPop').addEventListener('click',function(e){if(e.target===this)closeCal()});
function calNav(d){_calM+=d;if(_calM>11){_calM=0;_calY++}else if(_calM<0){_calM=11;_calY--}renderCal()}
function renderCal(){document.getElementById('calTitle').textContent=TMF[_calM]+' '+_calY;var first=new Date(_calY,_calM,1).getDay(),days=new Date(_calY,_calM+1,0).getDate();var h='';for(var i=0;i<first;i++)h+='<div class="cal-d empty"></div>';var todayK=dKey(NOW),selK=dKey(viewDate);for(var d=1;d<=days;d++){var dk=_calY+'-'+String(_calM+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');var cls='cal-d';if(dk===todayK)cls+=' today';if(dk===selK)cls+=' sel';h+='<div class="'+cls+'" onclick="pickDay('+_calY+','+_calM+','+d+')">'+d+'</div>'}document.getElementById('calDays').innerHTML=h}
function pickDay(y,m,d){viewDate=new Date(y,m,d);closeCal();render()}

/* ===== PILL MONTH PICKER (Monthly) ===== */
var _mpY;
function pillMonthH(){return '<div class="pill-date"><div class="pill-btn" onclick="openMP()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5"><rect x="3" y="4" width="18" height="18" rx="2"/><path d="M3 10h18M8 2v4M16 2v4"/></svg><span>'+TMF[sM_]+' '+cY+'</span><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><polyline points="6 9 12 15 18 9"/></svg></div></div>'}
function openMP(){_mpY=cY;renderMP();document.getElementById('mpPop').classList.add('open')}
function closeMP(){document.getElementById('mpPop').classList.remove('open')}
document.getElementById('mpPop').addEventListener('click',function(e){if(e.target===this)closeMP()});
function mpNav(d){_mpY+=d;renderMP()}
function renderMP(){document.getElementById('mpTitle').textContent=String(_mpY);var h='';for(var m=0;m<12;m++){var cls='mp-item';if(_mpY===cY&&m===sM_)cls+=' sel';if(isP(_mpY,m))cls+=' off';h+='<div class="'+cls+'" onclick="pickMonth('+_mpY+','+m+')">'+TMF[m]+'</div>'}document.getElementById('mpGrid').innerHTML=h}
function pickMonth(y,m){cY=y;sM_=m;closeMP();render()}
/* ===== CALC ===== */
function calc(y,m){
var d=gm(y,m),iB=Number(d.sal||0);
var iO=d.oI.filter(function(x){return x.ck}).reduce(function(s,x){return s+Number(x.a||0)},0);
var tI=iB+iO;
var fE=Number(d.food||0)+Number(d.sav||0)+Number(d.shopee||0)+Number(d.gas||0);
gCats().forEach(function(c){fE+=Number(d[c.id]||0)});
var otherTotal=getDailyOtherTotal(y,m);
var savTransfer=getSavingsTransferFromRemaining(y,m);
var tE=fE+otherTotal+savTransfer;
return{tI:tI,tE:tE,r:tI-tE,d:d,otherTotal:otherTotal,savTransfer:savTransfer}
}

function render(){var el=document.getElementById('M');renderThemeDD();if(vw==='d')rDaily(el);else if(vw==='y')rYear(el);else if(vw==='sim')rSim(el);else rMonth(el)}

function heroH(lb,val,tI,tE){
return '<div class="hero '+(val>=0?'pos':'neg')+'" style="animation:fadeUp .3s ease both"><div class="hero-mesh"><div class="orb"></div><div class="orb"></div><div class="orb"></div></div><div class="hero-lb">'+lb+'</div><div class="hero-v">'+(val>=0?'':'-')+fmt(Math.abs(val))+'.-</div><div class="hero-row"><div class="hero-s"><small>\u0E23\u0E32\u0E22\u0E23\u0E31\u0E1A</small><span>+'+fmt(tI)+'</span></div><div class="hero-s"><small>\u0E23\u0E32\u0E22\u0E08\u0E48\u0E32\u0E22</small><span>-'+fmt(tE)+'</span></div></div></div>'}

function savTabH(savBal){
var s=gs(),hidden=!!s.savHidden;
var h='<div class="sav-bar"><div class="sav-bar-l" onclick="openSavings()">'+IC.save+'<span>\u0E40\u0E07\u0E34\u0E19\u0E40\u0E01\u0E47\u0E1A</span></div><div class="sav-bar-r"><span class="sav-bar-amt '+(hidden?'hide':'')+'" onclick="openSavings()">'+fmt(savBal)+'.-</span><span class="sav-bar-amt-mask '+(hidden?'':'hide')+'" onclick="openSavings()">'+fmt(savBal).replace(/[0-9]/g,'*')+'.-</span><button class="sav-bar-eye" onclick="event.stopPropagation();toggleSavHide(!getSavHidden())" title="'+(hidden?'\u0E41\u0E2A\u0E14\u0E07':'\u0E0B\u0E48\u0E2D\u0E19')+'"><svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5">'+(hidden?'<path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/>':'<path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/>')+'</svg></button></div></div>';
return h}
function getSavHidden(){var s=gs();return!!s.savHidden}
function toggleSavHide(v){var s=gs();s.savHidden=v;syncNow(s);render()}

function progBar(spent,budget){
    if(!budget||budget<=0)return'';
    var pct=Math.min((spent/budget)*100,100);
    // Color logic: Green (<70% spent), Orange (70-90%), Red (>90%)
    var cls=pct<70?'pf-gn':pct<90?'pf-or':'pf-rd';
    return '<div class="prog-wrap"><div class="prog-bar"><div class="prog-fill '+cls+'" style="width:'+pct+'%"></div></div></div>';
}

function getAllExpCats(d){
var exps=[{k:'food',n:'\u0E04\u0E48\u0E32\u0E01\u0E34\u0E19',c:'food',ic:'food'},{k:'sav',n:'\u0E40\u0E07\u0E34\u0E19\u0E2D\u0E2D\u0E21',c:'save',ic:'save'},{k:'shopee',n:'Shopee',c:'shopee',ic:'shopee',hasCal:true},{k:'gas',n:'\u0E04\u0E48\u0E32\u0E19\u0E49\u0E33\u0E21\u0E31\u0E19',c:'gas',ic:'gas'}];
gCats().forEach(function(cat){exps.push({k:cat.id,n:cat.name,c:'custom',ic:cat.id,isCustom:true})});
return exps}

/* ===== RENDER MONTHLY ===== */
function rMonth(el){
var y=cY,m=sM_,p=isP(y,m),d=gm(y,m),c=calc(y,m);
var savBal=getSavings().balance;
var h=pillMonthH();
h+=heroH('\u0E40\u0E07\u0E34\u0E19\u0E04\u0E07\u0E40\u0E2B\u0E25\u0E37\u0E2D '+TMF[m]+' '+cY,c.r,c.tI,c.tE);
h+=savTabH(savBal);
var _sk=getStreak();if(_sk.current>0){h+='<div class="streak-bar" onclick="openReport()"><span>🔥 บันทึกต่อเนื่อง '+_sk.current+' วัน</span><span class="streak-best">สถิติดีสุด '+_sk.best+' วัน</span></div>'}
h+='<div style="display:flex;gap:6px;padding:0 2px 8px"><button class="btn btn-gh" style="flex:1;font-size:11px;padding:6px 10px" onclick="openReport()"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="margin-right:4px"><path d="M3 3v18h18"/><path d="M18 17V9l-5 5-3-3-5 5"/></svg>รายงาน</button><button class="btn btn-gh" style="flex:1;font-size:11px;padding:6px 10px" onclick="openRC()"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="margin-right:4px"><path d="M17 1l4 4-4 4"/><path d="M3 11V9a4 4 0 014-4h14"/><path d="M7 23l-4-4 4-4"/><path d="M21 13v2a4 4 0 01-4 4H3"/></svg>ประจำ</button><button class="btn btn-gh" style="flex:1;font-size:11px;padding:6px 10px" onclick="openSG()"><svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" style="margin-right:4px"><circle cx="12" cy="12" r="10"/><path d="M12 6v6l4 2"/></svg>เป้าหมาย</button></div>';

if(!p)h+='<div class="abar"><span>\u0E04\u0E31\u0E14\u0E25\u0E2D\u0E01\u0E04\u0E48\u0E32\u0E19\u0E35\u0E49\u0E44\u0E1B\u0E17\u0E38\u0E01\u0E40\u0E14\u0E37\u0E2D\u0E19</span><button class="btn btn-ac" style="padding:5px 11px;font-size:11px" onclick="apAll()">\u0E43\u0E0A\u0E49\u0E01\u0E31\u0E1A\u0E17\u0E38\u0E01\u0E40\u0E14\u0E37\u0E2D\u0E19</button></div>';

// INCOME
h+='<div class="sec" style="animation-delay:.04s"><div class="sec-t"><span>\u0E23\u0E32\u0E22\u0E23\u0E31\u0E1A</span>'+(p?'':'<button class="tgl'+(editInc?' on':'')+'" onclick="editInc=!editInc;render()"></button>')+'</div><div class="sc">';
h+='<div class="row"><div class="ri inc">'+IC.inc+'</div><div class="rn"><div class="rn-t">\u0E40\u0E07\u0E34\u0E19\u0E40\u0E14\u0E37\u0E2D\u0E19</div></div>';
if(editInc&&!p)h+='<input class="edit-val" type="number" id="ed_sal" value="'+d.sal+'" onchange="saveField(\'sal\',\'ed_sal\')">';
else h+='<div class="rv pos">'+fmt(d.sal)+'.-</div>';
h+='</div>';
if(d.oI.length>0){h+='<div class="sub-lb">\u0E23\u0E32\u0E22\u0E44\u0E14\u0E49\u0E2D\u0E37\u0E48\u0E19\u0E46</div>';d.oI.forEach(function(x,i){h+=ciItem(x,i,'I',p)})}
if(!p)h+='<div class="ar"><input class="inp" type="number" id="iA" placeholder="\u0E08\u0E33\u0E19\u0E27\u0E19\u0E40\u0E07\u0E34\u0E19" min="0" style="flex:.55"><input class="inp" id="iN" placeholder="\u0E42\u0E19\u0E49\u0E15" style="flex:1"><button class="btn btn-gn" style="padding:8px 11px" onclick="addI()">+</button></div>';
h+='</div></div>';

// EXPENSES
h+='<div class="sec" style="animation-delay:.08s"><div class="sec-t"><span>\u0E23\u0E32\u0E22\u0E08\u0E48\u0E32\u0E22</span>'+(p?'':'<button class="tgl'+(editExp?' on':'')+'" onclick="editExp=!editExp;render()"></button>')+'</div><div class="sc">';
var exps=getAllExpCats(d);
exps.forEach(function(e){
var v=Number(d[e.k]||0);
var isShopee=e.k==='shopee';
h+='<div class="row"><div class="ri '+e.c+'">'+(e.isCustom?getCatIcon(e.k):(IC[e.ic]||IC.food))+'</div><div class="rn"><div class="rn-t" style="display:flex;align-items:center;gap:6px">'+e.n+(e.hasCal?'<button class="mini-btn" style="width:24px;height:24px" onclick="event.stopPropagation();openShopee()">'+IC.cal+'</button>':'')+'</div></div>';
if(editExp&&!p&&!isShopee)h+='<input class="edit-val" type="number" id="ed_'+e.k+'" value="'+v+'" onchange="saveField(\''+e.k+'\',\'ed_'+e.k+'\')" step="0.01">';
else h+='<div class="rv neg">'+fmt(v)+'.-</div>';
h+='</div>';
});

// Add cat btn
if(!p)h+='<div style="padding:4px 10px 8px"><button class="add-cat-btn" onclick="openCat()"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="16"/><line x1="8" y1="12" x2="16" y2="12"/></svg>\u0E40\u0E1E\u0E34\u0E48\u0E21\u0E2B\u0E21\u0E27\u0E14\u0E04\u0E48\u0E32\u0E43\u0E0A\u0E49\u0E08\u0E48\u0E32\u0E22</button></div>';

// Other expenses from daily log (auto)
var otherItems=getDailyOther(y,m);
if(otherItems.length>0||c.otherTotal>0){
h+='<div class="sub-lb">\u0E04\u0E48\u0E32\u0E43\u0E0A\u0E49\u0E08\u0E48\u0E32\u0E22\u0E2D\u0E37\u0E48\u0E19\u0E46 (\u0E08\u0E32\u0E01\u0E1A\u0E31\u0E19\u0E17\u0E36\u0E01\u0E23\u0E32\u0E22\u0E27\u0E31\u0E19) <span style="font-family:JetBrains Mono,monospace;font-size:11px;font-weight:700;color:var(--rd)">'+fmt(c.otherTotal)+'.-</span></div>';
otherItems.forEach(function(x){h+='<div class="ci"><div class="rn"><div class="rn-t" style="font-size:12px;color:var(--rd)">'+fmt(x.a)+'.- '+(x.n?'<span style="color:var(--tx2);font-weight:500">'+esc(x.n)+'</span>':'')+'</div><div class="rn-s">'+x.date+' '+x.t+'</div></div></div>'})}
h+='</div></div>';

// Savings goal
if(editExp&&!p){var sg=gSet().savGoal||50000;h+='<div class="sec"><div class="sec-t">\u0E40\u0E1B\u0E49\u0E32\u0E2B\u0E21\u0E32\u0E22\u0E2D\u0E2D\u0E21\u0E23\u0E32\u0E22\u0E1B\u0E35</div><div class="sc" style="padding:10px 14px"><div style="display:flex;align-items:center;justify-content:space-between"><span style="font-size:13px;font-weight:600">\u0E40\u0E1B\u0E49\u0E32\u0E2B\u0E21\u0E32\u0E22</span><input class="edit-val" type="number" id="ed_savGoal" value="'+sg+'" onchange="saveSavGoal()"></div></div></div>'}

// Chart
var gl=isGuest?' guest-lock':'';
h+='<div class="sec glass-chart'+gl+'" style="animation-delay:.12s"'+(isGuest?' onclick="showPrem()"':'')+'><div class="sec-t">สัดส่วนรายจ่ายแบ่งตามหมวดหมู่</div><div class="sc" style="padding:14px 10px"><div class="cw"><canvas id="mC"></canvas></div></div>';
if(isGuest)h+='<div class="guest-lock-label"><svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="11" width="18" height="11" rx="2"/><path d="M7 11V7a5 5 0 0110 0v4"/></svg>\u0E2A\u0E21\u0E31\u0E04\u0E23\u0E2A\u0E21\u0E32\u0E0A\u0E34\u0E01</div>';
h+='</div>';
if(!p)h+='<div class="reset-area"><button class="reset-btn" onclick="resetMonth()">\u0E25\u0E49\u0E32\u0E07\u0E40\u0E14\u0E37\u0E2D\u0E19 '+TM[m]+'</button><div class="credit">Credit : Opus 4.6 & Jarasrawee</div></div>';
else h+='<div class="credit">Credit : Opus 4.6 & Jarasrawee</div>';
el.innerHTML=h;if(!isGuest)drawMC(d,y,m)
}

/* ===== RENDER DAILY ===== */
function rDaily(el){
var dk=dKey(viewDate),log=getDayLog(dk),total=log.reduce(function(s,x){return s+Number(x.a||0)},0);
var vy=viewDate.getFullYear(),vm=viewDate.getMonth();
var c=calc(vy,vm),d=c.d,savBal=getSavings().balance;

var h=pillDateH();

// Hero
h+=heroH('\u0E40\u0E07\u0E34\u0E19\u0E04\u0E07\u0E40\u0E2B\u0E25\u0E37\u0E2D '+TMF[vm]+' '+vy,c.r,c.tI,c.tE);
h+=savTabH(savBal);

// Budget overview with progress
h+='<div class="sec"><div class="sec-t">\u0E07\u0E1A\u0E23\u0E32\u0E22\u0E40\u0E14\u0E37\u0E2D\u0E19</div><div class="sc">';
var exps=getAllExpCats(d);
exps.forEach(function(e){var budget=Number(d[e.k]||0);if(budget<=0)return;var spent=getDailySpent(vy,vm,e.k);var left=budget-spent;var isShopee=e.k==='shopee';
h+='<div class="row'+((!isShopee)?' has-prog':'')+'"><div class="ri '+e.c+'" style="width:30px;height:30px">'+(e.isCustom?getCatIcon(e.k):(IC[e.ic]||IC.food))+'</div><div class="rn"><div class="rn-t" style="font-size:12px">'+e.n+'</div>'+((!isShopee)?'<div class="rn-s">\u0E40\u0E2B\u0E25\u0E37\u0E2D '+fmt(left)+' / '+fmt(budget)+'</div>':'')+'</div><div class="rv '+(left>=0?'':'neg')+'" style="font-size:13px">'+fmt(left)+'.-</div></div>';
if(!isShopee)h+=progBar(spent,budget)});
h+='</div></div>';

// Today's entries
var filteredLog = log.filter(function(x){
    if(!sq) return true;
    var n = (x.n||'').toLowerCase();
    var cat = (getAllDailyCats().find(c2 => c2.id === x.cat)||{name:''}).name.toLowerCase();
    return n.indexOf(sq.toLowerCase()) >= 0 || cat.indexOf(sq.toLowerCase()) >= 0;
});

h+='<div class="sec"><div class="sec-t"><span>\u0E23\u0E32\u0E22\u0E08\u0E48\u0E32\u0E22\u0E27\u0E31\u0E19\u0E19\u0E35\u0E49</span> <span style="font-family:JetBrains Mono,monospace;font-size:11px;color:var(--rd)">-'+fmt(total)+'.-</span></div>';

// Search Bar
h+='<div class="search-wrap"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg><input type="text" placeholder="ค้นหาบันทึกหรือหมวดหมู่..." oninput="sq=this.value;rDailyList()" id="sqI" value="'+sq+'"></div>';

h+='<div id="dailyList">';
h+=dailyListH(filteredLog, dk);
h+='</div></div>';

// Weekly + Monthly summary
var weekT=0,weekD=0;for(var i=0;i<7;i++){var wd=new Date(viewDate);wd.setDate(wd.getDate()-wd.getDay()+i);var wl=getDayLog(dKey(wd));var wt=wl.reduce(function(s2,x){return s2+Number(x.a||0)},0);if(wt>0)weekD++;weekT+=wt}
h+='<div class="sec"><div class="sec-t">\u0E2A\u0E23\u0E38\u0E1B</div><div class="sc" style="padding:14px"><div style="display:flex;justify-content:space-between;font-size:13px;font-weight:600"><span>\u0E2A\u0E31\u0E1B\u0E14\u0E32\u0E2B\u0E4C\u0E19\u0E35\u0E49</span><span class="rv neg" style="font-size:14px">-'+fmt(weekT)+'.-</span></div><div style="font-size:11px;color:var(--tx3);margin-top:4px">'+weekD+' \u0E27\u0E31\u0E19'+(weekD>0?' \u0E40\u0E09\u0E25\u0E35\u0E48\u0E22 '+fmt(Math.round(weekT/weekD))+'.-/\u0E27\u0E31\u0E19':'')+'</div>';
// Monthly
var mDays=new Date(vy,vm+1,0).getDate(),mT=0,mC2=0;
for(var d2=1;d2<=mDays;d2++){var ml=getDayLog(vy+'-'+String(vm+1).padStart(2,'0')+'-'+String(d2).padStart(2,'0'));ml.forEach(function(x){mT+=Number(x.a||0);mC2++})}
h+='<div style="display:flex;justify-content:space-between;font-size:13px;font-weight:600;margin-top:10px;padding-top:10px;border-top:1px solid var(--cb)"><span>\u0E40\u0E14\u0E37\u0E2D\u0E19 '+TMF[vm]+'</span><span class="rv neg" style="font-size:14px">-'+fmt(mT)+'.-</span></div><div style="font-size:11px;color:var(--tx3);margin-top:4px">'+mC2+' \u0E23\u0E32\u0E22\u0E01\u0E32\u0E23</div>';
h+='</div></div>';
h+='<div class="credit">Credit : Opus 4.6 & Jarasrawee</div>';
el.innerHTML=h}
function dailyListH(log, dk){
    var h = '';
    if(log.length > 0){
        h += '<div class="sc">';
        var allCats = getAllDailyCats();
        log.slice().reverse().forEach(function(x, ri){
            var i = log.length - 1 - ri;
            var cat = allCats.find(function(c2){ return c2.id === x.cat }) || {name:'อื่นๆ', c:'other', id:'other'};
            h += '<div class="dl-item"><div class="dl-time">'+x.t+'</div><div class="ri '+cat.c+'" style="width:30px;height:30px">'+(cat.ic?getCatIcon(cat.id):(IC[cat.id]||IC.other))+'</div><div class="rn"><div class="rn-t" style="font-size:12.5px">'+fmt(x.a)+'.-</div>'+(x.n?'<div class="rn-s">'+esc(x.n)+'</div>':'')+'</div><button class="cd" onclick="delDayItem(\''+dk+'\','+i+')">'+IC.dl+'</button></div>';
        });
        h += '</div>';
    } else {
        h += '<div class="dl-empty"><svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="var(--tx3)" stroke-width="1.5" style="margin-bottom:8px"><path d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/><polyline points="14 2 14 8 20 8"/></svg><div>'+(sq?'ไม่พบผลลัพธ์ที่ค้นหา':'ยังไม่มีรายการ')+'</div></div>';
    }
    return h;
}

function rDailyList(){
    var dk = dKey(viewDate), log = getDayLog(dk);
    var filteredLog = log.filter(function(x){
        if(!sq) return true;
        var n = (x.n||'').toLowerCase();
        var cat = (getAllDailyCats().find(c2 => c2.id === x.cat)||{name:''}).name.toLowerCase();
        return n.indexOf(sq.toLowerCase()) >= 0 || cat.indexOf(sq.toLowerCase()) >= 0;
    });
    var el = document.getElementById('dailyList');
    if(el) el.innerHTML = dailyListH(filteredLog, dk);
}
function rYear(el){var h='',ti=0,te=0,ts=0,rows=[];for(var m=0;m<12;m++){var c=calc(cY,m);ti+=c.tI;te+=c.tE;ts+=Number(c.d.sav||0);rows.push(c)}var tr=ti-te,goal=gSet().savGoal||50000,prog=goal>0?Math.min((ts/goal)*100,100):0;
h+=heroH('\u0E2A\u0E23\u0E38\u0E1B\u0E23\u0E32\u0E22\u0E1B\u0E35 '+cY,tr,ti,te);
h+=savTabH(getSavings().balance);
h+='<div class="sec"><div class="sec-t"><span>\u0E40\u0E1B\u0E49\u0E32\u0E2B\u0E21\u0E32\u0E22\u0E2D\u0E2D\u0E21\u0E23\u0E32\u0E22\u0E1B\u0E35</span> <span class="rv pos" style="font-size:12px">'+prog.toFixed(0)+'%</span></div><div class="sc"><div style="padding:4px 16px 0;font-size:11px;color:var(--tx3)">\u0E2D\u0E2D\u0E21\u0E41\u0E25\u0E49\u0E27 '+fmt(ts)+' / '+fmt(goal)+'.-</div><div class="prog-wrap"><div class="prog-bar"><div class="prog-fill pf-gn" style="width:'+Math.min(prog,100)+'%"></div></div></div></div></div>';
h+='<div class="sec"><div class="sec-t">\u0E15\u0E32\u0E23\u0E32\u0E07</div><div class="sc" style="padding:0;overflow-x:auto"><table class="yt"><thead><tr><th>\u0E40\u0E14\u0E37\u0E2D\u0E19</th><th>\u0E23\u0E31\u0E1A</th><th>\u0E08\u0E48\u0E32\u0E22</th><th>\u0E40\u0E2B\u0E25\u0E37\u0E2D</th></tr></thead><tbody>';
rows.forEach(function(c,i){h+='<tr><td>'+TM[i]+'</td><td>'+fmt(c.tI)+'</td><td>'+fmt(c.tE)+'</td><td style="'+(c.r>=0?'color:var(--gn)':'color:var(--rd)')+'">'+(c.r>=0?'+':'')+fmt(c.r)+'</td></tr>'});
h+='</tbody><tfoot><tr><td>\u0E23\u0E27\u0E21</td><td style="text-align:right;color:var(--gn)">'+fmt(ti)+'</td><td style="text-align:right;color:var(--rd)">'+fmt(te)+'</td><td style="text-align:right;'+(tr>=0?'color:var(--gn)':'color:var(--rd)')+'">'+(tr>=0?'+':'')+fmt(tr)+'</td></tr></tfoot></table></div></div>';
h+='<div class="sec"><div class="sec-t">\u0E01\u0E23\u0E32\u0E1F</div><div class="sc" style="padding:14px 10px"><div class="cw"><canvas id="yC"></canvas></div></div></div>';
h+='<div class="reset-area"><button class="reset-btn" onclick="resetYear()">\u0E25\u0E49\u0E32\u0E07\u0E1B\u0E35 '+cY+'</button><div class="credit">Credit : Opus 4.6 & Jarasrawee</div></div>';
el.innerHTML=h;drawYC(rows)}

/* ===== RENDER SIMULATOR ===== */
function rSim(el){
    var st=gs(),sims=st.sims||[];
    var h = '<div class="sec-t" style="margin-top:10px">จำลองการผ่อนชำระ</div>';
    h += '<div class="sim-card">';
    h += '<div class="sim-head">'+IC.shopee+' <span>Shopee Simulator</span></div>';
    h += '<div class="sim-body">';
    h += '<div class="sim-row"><label>ชื่อสินค้า / เป้าหมาย</label><input id="simName" placeholder="เช่น iPhone 16, PS5..."></div>';
    h += '<div class="sim-row"><label>ยอดผ่อนต่อเดือน (บาท)</label><input type="number" id="simPer" placeholder="0" min="0"></div>';
    h += '<div class="sim-row"><label>จำนวนงวด (เดือน)</label><input type="number" id="simMonths" placeholder="1" min="1" max="60"></div>';
    h += '<button class="sim-save-btn" style="margin-top:8px;background:linear-gradient(135deg, #EE4D2D, #FF7337)" onclick="runSim()">คำนวณผลกระทบรายเดือน</button>';
    h += '<div id="simResult"></div>';
    h += '</div></div>';
    
    if(sims.length > 0){
        h += '<div class="sec-t">รายการที่บันทึกไว้</div>';
        h += '<div class="sec"><div class="sc">';
        sims.forEach(function(s, i){
            h += '<div class="row"><div class="ri shopee">'+IC.shopee+'</div>';
            h += '<div class="rn"><div class="rn-t">'+esc(s.name)+'</div><div class="rn-s">'+s.months+' งวด x '+fmt(s.per)+'.-</div></div>';
            h += '<div style="display:flex;gap:6px"><button class="btn btn-ac" style="padding:6px 10px;font-size:11px" onclick="applySim('+i+')">ใช้จริง</button>';
            h += '<button class="cd" onclick="delSim('+i+')">'+IC.dl+'</button></div></div>';
        });
        h += '</div></div>';
    }
    h += '<div class="credit" style="margin-top:16px">Credit : Opus 4.6 & Jarasrawee</div>';
    el.innerHTML = h;
}

function runSim(){
    var nm=document.getElementById('simName').value||'-',per=Number(document.getElementById('simPer').value)||0,mos=Number(document.getElementById('simMonths').value)||0;
    if(per<=0||mos<=0)return;
    var h = '<div class="sim-result">';
    h += '<div class="sim-res-title"><span>ผลการจำลอง: '+esc(nm)+'</span><svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="22 7 13.5 15.5 8.5 10.5 2 17"/><polyline points="16 7 22 7 22 13"/></svg></div>';
    h += '<div class="sim-res-sub">ยอดผ่อน '+fmt(per)+'.- ทั้งหมด '+mos+' เดือน (รวม '+fmt(per*mos)+'.-)</div>';
    h += '<div style="max-height:240px;overflow-y:auto;margin:0 -4px;padding:0 4px"><table class="yt" style="font-size:11px"><thead><tr><th>เดือน</th><th>ปกติ</th><th>หลังผ่อน</th></tr></thead><tbody>';
    var sM=NOW.getMonth();
    for(var i=0; i<mos; i++){
        var mI=(sM+i)%12,yr=cY+Math.floor((sM+i)/12),cc=calc(yr,mI),aR=cc.r-per;
        h += '<tr><td>'+TM[mI]+(yr!==cY?' '+yr:'')+'</td><td style="text-align:right">'+fmt(cc.r)+'</td><td style="text-align:right;font-weight:800;'+(aR>=0?'color:var(--gn)':'color:var(--rd)')+'">'+(aR>=0?'+':'')+fmt(aR)+'</td></tr>';
    }
    h += '</tbody></table></div>';
    h += '<div class="sim-actions"><button class="sim-save-btn" onclick="saveSim()">บันทึกแผนการผ่อนนี้</button></div></div>';
    document.getElementById('simResult').innerHTML = h;
}
function saveSim(){var s=gs();if(!s.sims)s.sims=[];s.sims.push({name:document.getElementById('simName').value||'-',per:Number(document.getElementById('simPer').value)||0,months:Number(document.getElementById('simMonths').value)||0,startM:NOW.getMonth(),startY:cY});syncNow(s);render()}
function delSim(i){var s=gs();if(s.sims)s.sims.splice(i,1);syncNow(s);render()}
function applySim(i){if(!confirm('\u0E22\u0E37\u0E19\u0E22\u0E31\u0E19?'))return;var s=gs(),sm=s.sims[i];if(!sm)return;if(!s.shM)s.shM={};for(var j=0;j<sm.months;j++){var mI=(sm.startM+j)%12,yr=sm.startY+Math.floor((sm.startM+j)/12),k=mk(yr,mI);s.shM[k]=(Number(s.shM[k])||0)+sm.per;if(s.mo&&s.mo[k])s.mo[k].shopee=Number(s.shM[k])||0}s.sims.splice(i,1);syncNow(s);render()}

